(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>"']/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"capacity-utilization",fields:[{"key":"actualOutput","label":"실제 생산량","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"maximumOutput","label":"최대 생산능력","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"실제 생산량이 최대능력을 넘으면 100%를 초과할 수 있습니다.",compute:function(x){var a=Number(x.actualOutput),m=Number(x.maximumOutput);if(![a,m].every(Number.isFinite)||a<0||m<=0)return{error:"실제 생산량은 0 이상, 최대 생산능력은 0보다 크게 입력해 주세요."};return{utilization:a/m*100,unused:m-a,unusedRate:(m-a)/m*100};},format:function(r,api){return api.resultCard("가동률",api.formatNumber(r.utilization,2)+"%","")+api.resultCard("미사용 능력",api.formatNumber(r.unused,2),api.formatNumber(r.unusedRate,2)+"%");}},{id:"labor-productivity",fields:[{"key":"units","label":"완료 생산량·업무량","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"workers","label":"작업 인원","type":"integer","placeholder":"","default":"1","options":[],"raw":false},{"key":"hoursPerWorker","label":"1인당 작업시간","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var u=Number(x.units),w=Number(x.workers),h=Number(x.hoursPerWorker);if(![u,w,h].every(Number.isFinite)||u<0||!Number.isInteger(w)||w<=0||h<=0)return{error:"업무량은 0 이상, 인원은 0보다 큰 정수, 시간은 0보다 크게 입력해 주세요."};var labor=w*h;return{laborHours:labor,unitsPerLaborHour:u/labor,hoursPerUnit:u>0?labor/u:null};},format:function(r,api){return api.resultCard("시간당 생산성",api.formatNumber(r.unitsPerLaborHour,3)+" 단위/인시","")+api.resultCard("총 노동시간",api.formatNumber(r.laborHours,2)+" 인시","")+api.resultCard("단위당 노동시간",r.hoursPerUnit===null?"계산 불가":api.formatNumber(r.hoursPerUnit,4)+"시간","");}},{id:"defect-yield-rate",fields:[{"key":"totalUnits","label":"전체 생산수량","type":"integer","placeholder":"","default":"","options":[],"raw":false},{"key":"defectiveUnits","label":"불량 수량","type":"integer","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var t=Number(x.totalUnits),d=Number(x.defectiveUnits);if(!Number.isInteger(t)||!Number.isInteger(d)||t<=0||d<0||d>t)return{error:"전체 수량은 0보다 큰 정수, 불량 수량은 0 이상 전체 이하의 정수로 입력해 주세요."};var good=t-d;return{defectRate:d/t*100,yieldRate:good/t*100,goodUnits:good};},format:function(r,api){return api.resultCard("불량률",api.formatNumber(r.defectRate,3)+"%","")+api.resultCard("양품률·수율",api.formatNumber(r.yieldRate,3)+"%","")+api.resultCard("양품 수량",api.formatNumber(r.goodUnits,0)+"개","");}},{id:"return-rate-business",fields:[{"key":"soldUnits","label":"판매 수량","type":"integer","placeholder":"","default":"","options":[],"raw":false},{"key":"returnedUnits","label":"반품 수량","type":"integer","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var s=Number(x.soldUnits),r=Number(x.returnedUnits);if(!Number.isInteger(s)||!Number.isInteger(r)||s<=0||r<0||r>s)return{error:"판매 수량은 0보다 큰 정수, 반품 수량은 0 이상 판매 수량 이하로 입력해 주세요."};var kept=s-r;return{returnRate:r/s*100,keptUnits:kept,keepRate:kept/s*100};},format:function(r,api){return api.resultCard("반품률",api.formatNumber(r.returnRate,2)+"%","")+api.resultCard("정상 유지율",api.formatNumber(r.keepRate,2)+"%","")+api.resultCard("유지 수량",api.formatNumber(r.keptUnits,0)+"개","");}},{id:"order-fulfillment-rate",fields:[{"key":"receivedOrders","label":"접수 주문 수","type":"integer","placeholder":"","default":"","options":[],"raw":false},{"key":"fulfilledOrders","label":"처리 완료 주문 수","type":"integer","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var r=Number(x.receivedOrders),f=Number(x.fulfilledOrders);if(!Number.isInteger(r)||!Number.isInteger(f)||r<=0||f<0||f>r)return{error:"접수 주문은 0보다 큰 정수, 완료 주문은 0 이상 접수 주문 이하로 입력해 주세요."};var u=r-f;return{fulfillmentRate:f/r*100,unfulfilled:u,unfulfilledRate:u/r*100};},format:function(r,api){return api.resultCard("주문 처리율",api.formatNumber(r.fulfillmentRate,2)+"%","")+api.resultCard("미처리 주문",api.formatNumber(r.unfulfilled,0)+"건",api.formatNumber(r.unfulfilledRate,2)+"%");}},{id:"average-handling-time",fields:[{"key":"talkMinutes","label":"총 상담시간 (분)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"holdMinutes","label":"총 대기시간 (분)","type":"number","placeholder":"","default":"0","options":[],"raw":false},{"key":"afterCallMinutes","label":"총 후처리시간 (분)","type":"number","placeholder":"","default":"0","options":[],"raw":false},{"key":"contacts","label":"처리 건수","type":"integer","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var t=Number(x.talkMinutes),h=Number(x.holdMinutes),a=Number(x.afterCallMinutes),c=Number(x.contacts);if(![t,h,a,c].every(Number.isFinite)||t<0||h<0||a<0||!Number.isInteger(c)||c<=0)return{error:"각 시간은 0 이상, 처리 건수는 0보다 큰 정수로 입력해 주세요."};var total=t+h+a;return{totalMinutes:total,ahtMinutes:total/c,talkPerContact:t/c};},format:function(r,api){return api.resultCard("평균 처리시간",api.formatNumber(r.ahtMinutes,2)+"분/건","")+api.resultCard("총 처리시간",api.formatNumber(r.totalMinutes,1)+"분","")+api.resultCard("평균 상담시간",api.formatNumber(r.talkPerContact,2)+"분/건","");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
